import{c as s}from"./DffLFeIZ.js";const r={async getAll(){return(await s.get("/lab-technicians")).data},async getGroups(){return(await s.get("/lab-technicians/groups")).data},async createGroup(e){return(await s.post("/lab-technicians/groups",e)).data},async updateGroup(e,a){return(await s.put(`/lab-technicians/groups/${e}`,a)).data},async deleteGroup(e){return(await s.delete(`/lab-technicians/groups/${e}`)).data},async getMe(){return(await s.get("/lab-technicians/me")).data},async selectActiveLab(e){return(await s.put("/lab-technicians/me/lab",{lab_id:e})).data},async getDashboard(){return(await s.get("/lab-technicians/me/dashboard")).data},async getReport(e){return(await s.get(`/lab-technicians/reports/${e}`)).data},async acceptReport(e){return(await s.post(`/lab-technicians/reports/${e}/accept`)).data},async saveResults(e,a){return(await s.put(`/lab-technicians/reports/${e}/results`,a)).data}};export{r as l};
